import { QueryCache, CacheKey } from '@/lib'

const cache = QueryCache.getInstance()
const key = CacheKey.fromQuery('users', {
  filters: [{ column: 'status', operator: 'eq', value: 'active' }],
  orderBy: [{ column: 'created_at', ascending: false }],
  limit: 20,
})

// Check cache first
const cached = cache.get(key)
if (cached) return cached

// Execute query and cache result
const result = await fetchAll('users', { filters: [...], limit: 20 })
cache.set(key, result, 60000) // 1 minute TTL
return result

import { QueryCache, CacheKey, insertOne } from '@/lib'

// Insert automatically invalidates cache
const newUser = await insertOne('users', { name: 'John', email: 'john@example.com' })
// Cache automatically invalidated for 'users' table

// Manual invalidation if needed
const cache = QueryCache.getInstance()
cache.invalidatePattern(CacheKey.tablePrefix('users'))

